/**
 * Semantic Gate Utilities
 * Part of SD-LEO-FEAT-SEMANTIC-VALIDATION-GATES-002
 *
 * Shared helpers for semantic validation gates:
 * - Confidence scoring based on data completeness
 * - Auto-fix detection (artifacts generated by AUTO_HOOK)
 * - SD-type applicability checking
 * - Semantic gate result builder
 */

/**
 * SD-type applicability matrix for semantic gates.
 * REQ = Required (blocking), OPT = Optional (warning), SKIP = Not applicable
 */
export const SEMANTIC_GATE_APPLICABILITY = {
  SCOPE_AUDIT:                    { feature: 'REQ', bugfix: 'REQ', infrastructure: 'OPT', documentation: 'SKIP', security: 'REQ', refactor: 'OPT', orchestrator: 'SKIP', database: 'REQ', enhancement: 'OPT' },
  DELIVERABLES_COMPLETENESS:      { feature: 'REQ', bugfix: 'REQ', infrastructure: 'OPT', documentation: 'SKIP', security: 'REQ', refactor: 'REQ', orchestrator: 'SKIP', database: 'REQ', enhancement: 'REQ' },
  CHILD_SCOPE_COVERAGE:           { feature: 'SKIP', bugfix: 'SKIP', infrastructure: 'SKIP', documentation: 'SKIP', security: 'SKIP', refactor: 'SKIP', orchestrator: 'REQ', database: 'SKIP', enhancement: 'SKIP' },
  VISION_DIMENSION_COMPLETENESS:  { feature: 'REQ', bugfix: 'OPT', infrastructure: 'OPT', documentation: 'SKIP', security: 'REQ', refactor: 'SKIP', orchestrator: 'SKIP', database: 'REQ', enhancement: 'REQ' },
  SMOKE_TEST_VALIDATION:          { feature: 'REQ', bugfix: 'OPT', infrastructure: 'OPT', documentation: 'SKIP', security: 'REQ', refactor: 'SKIP', orchestrator: 'SKIP', database: 'OPT', enhancement: 'OPT' },
  SCOPE_REDUCTION_VERIFICATION:   { feature: 'REQ', bugfix: 'REQ', infrastructure: 'REQ', documentation: 'SKIP', security: 'REQ', refactor: 'REQ', orchestrator: 'REQ', database: 'REQ', enhancement: 'OPT' },
  ARCHITECTURE_REQUIREMENT_TRACE: { feature: 'REQ', bugfix: 'OPT', infrastructure: 'REQ', documentation: 'SKIP', security: 'REQ', refactor: 'OPT', orchestrator: 'SKIP', database: 'REQ', enhancement: 'OPT' },
  USER_STORY_COVERAGE:            { feature: 'REQ', bugfix: 'REQ', infrastructure: 'OPT', documentation: 'SKIP', security: 'REQ', refactor: 'SKIP', orchestrator: 'SKIP', database: 'OPT', enhancement: 'REQ' },
  OVERLAPPING_SCOPE_DETECTION:    { feature: 'REQ', bugfix: 'REQ', infrastructure: 'REQ', documentation: 'OPT', security: 'REQ', refactor: 'REQ', orchestrator: 'REQ', database: 'REQ', enhancement: 'REQ' }
};

/**
 * Check gate applicability for a given SD type.
 * @param {string} gateName - Key in SEMANTIC_GATE_APPLICABILITY
 * @param {string} sdType - SD type (feature, bugfix, etc.)
 * @returns {{ applicable: boolean, level: string }} Applicability result
 */
export function getGateApplicability(gateName, sdType) {
  const matrix = SEMANTIC_GATE_APPLICABILITY[gateName];
  if (!matrix) return { applicable: true, level: 'REQ' };

  const normalizedType = (sdType || 'feature').toLowerCase();
  const level = matrix[normalizedType] || 'REQ'; // Default to required for unknown types

  return {
    applicable: level !== 'SKIP',
    level
  };
}

/**
 * Compute confidence score based on data completeness.
 * @param {Object} params
 * @param {number} params.dataPoints - Number of data points available
 * @param {number} params.expectedPoints - Number of data points expected
 * @param {boolean} [params.hasDatabase=true] - Whether database data was available
 * @returns {number} Confidence score 0.0-1.0
 */
export function computeConfidence({ dataPoints, expectedPoints, hasDatabase = true }) {
  if (!hasDatabase) return 0.3;
  if (expectedPoints === 0) return 1.0;

  const ratio = Math.min(dataPoints / expectedPoints, 1.0);
  // Scale: 0.5 base (we have DB access) + 0.5 * data completeness
  return Math.round((0.5 + 0.5 * ratio) * 100) / 100;
}

/**
 * Detect auto-generated artifacts that should score lower.
 * @param {Object} item - Deliverable, story, or other artifact
 * @returns {boolean} True if auto-generated
 */
export function isAutoGenerated(item) {
  if (!item) return false;

  const markers = [
    item.generated_by === 'AUTO_HOOK',
    item.trigger_event === 'AUTO_FIX',
    item.created_by === 'auto-fix-guardian',
    item.metadata?.auto_generated === true,
    item.metadata?.source === 'auto-completion'
  ];

  return markers.some(Boolean);
}

/**
 * Build a standardized semantic gate result.
 * @param {Object} params
 * @param {boolean} params.passed
 * @param {number} params.score - 0-100
 * @param {number} [params.maxScore=100]
 * @param {number} params.confidence - 0.0-1.0
 * @param {string[]} [params.issues=[]]
 * @param {string[]} [params.warnings=[]]
 * @param {Object} [params.details={}]
 * @param {string} [params.remediation]
 * @returns {Object} Normalized gate result
 */
export function buildSemanticResult({ passed, score, maxScore = 100, confidence, issues = [], warnings = [], details = {}, remediation }) {
  // If confidence is low, degrade blocking to warning
  const effectivePassed = confidence < 0.7 ? true : passed;
  const lowConfidenceWarning = confidence < 0.7 && !passed
    ? [`Low confidence (${confidence}) — degraded from blocking to warning`]
    : [];

  return {
    passed: effectivePassed,
    score,
    maxScore,
    confidence,
    semantic: true,
    issues: effectivePassed ? [] : issues,
    warnings: [...warnings, ...lowConfidenceWarning],
    details: { ...details, confidence, semantic: true },
    ...(remediation && !effectivePassed ? { remediation } : {})
  };
}

/**
 * Build a skip result for non-applicable SD types.
 * @param {string} gateName
 * @param {string} sdType
 * @returns {Object} Skip result
 */
export function buildSkipResult(gateName, sdType) {
  return {
    passed: true,
    score: 100,
    maxScore: 100,
    confidence: 1.0,
    semantic: true,
    issues: [],
    warnings: [`${gateName} skipped for SD type: ${sdType}`],
    skipReason: 'NON_APPLICABLE_SD_TYPE',
    details: { sd_type: sdType, skipped: true, semantic: true }
  };
}
